{"stdout":""""Shared redactor + secret-scan gate for captured API traffic.

Used by the loopback ``POST /capture`` route (authoritative, receiver-side
redaction) and any capture-import CLI. A byte-for-byte behavioral twin lives in
``undermind-companion/redactor.mjs`` (page/extension side); the two MUST stay
equivalent — a drift between them is a security hole. Both are pinned by the
24-vector battery (``tests/test_sanitize.py`` / ``redactor.test.mjs``).

DO NOT regenerate or "improve" these patterns. They were tested against vectors
including two silent-corruption bugs: UUID ``project_id``/``job_id`` and
``author`` fields being over-redacted.
"""

from __future__ import annotations

import re
from typing import Any, cast

SENSITIVE_KEY = (r"(sessionid|session|(?:app-)?csrftoken|csrf|authorization|auth|bearer|token|"
    r"access[_-]?token|refresh[_-]?token|id[_-]?token|api[_-]?key|apikey|key|secret|"
    r"client[_-]?secret|password|passwd|pwd|sig|signature|code|state|nonce|companion[_-]?token)")
# Strong segments: never appear inside benign identifiers (author, status_code, keyboard, ...).
STRONG_SEG = {"csrftoken","csrf","token","sessionid","authorization","bearer","password",
    "passwd","secret","apikey","accesstoken","refreshtoken","idtoken","clientsecret",
    "companiontoken","signature"}
UUID = re.compile(r"^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$")
_PATS = [
    (re.compile(r"sessionid=[^;&\s\"']+", re.I), None),
    (re.compile(r"(app-)?csrftoken=[A-Za-z0-9]{8,}", re.I), None),
    (re.compile(r"Bearer\s+[A-Za-z0-9._\-]{12,}", re.I), None),
    (re.compile(SENSITIVE_KEY + r"=[^;&\s\"']{6,}", re.I), None),
    (re.compile(SENSITIVE_KEY + r"\"\s*:\s*\"[^\"]{6,}\"", re.I), None),
    (re.compile(r"\b[A-Za-z0-9_\-]{32,}\b"), "uuid_skip"),  # generic net, but keep UUIDs
]
_WHOLE_KEY = re.compile(r"^" + SENSITIVE_KEY + r"$", re.I)


def redact_str(s: Any) -> Any:
    if not isinstance(s, str):
        return s
    for pat, mode in _PATS:
        if mode == "uuid_skip":
            s = pat.sub(lambda m: m.group(0) if UUID.match(m.group(0)) else "<REDACTED>", s)
        else:
            s = pat.sub("<REDACTED>", s)
    return s


def _segs(k: str) -> list[str]:
    k = re.sub(r"([a-z0-9])([A-Z])", r"\1 \2", k)
    return [x.lower() for x in re.split(r"[^A-Za-z0-9]+", k) if x]


def key_sensitive(k: str) -> bool:
    norm = re.sub(r"[_\-\s]", "", k.lower())
    if _WHOLE_KEY.match(norm):          # whole key: code/state/key/apikey/csrftoken/...
        return True
    return any(seg in STRONG_SEG for seg in _segs(k))  # strong segments only


def redact_obj(o: Any) -> Any:
    if isinstance(o, list):
        return [redact_obj(x) for x in cast("list[Any]", o)]
    if isinstance(o, dict):
        return {
            k: ("<REDACTED>" if key_sensitive(k) else redact_obj(v))
            for k, v in cast("dict[Any, Any]", o).items()
        }
    return redact_str(o)


def scan_for_secrets(blob: str) -> list[str]:
    """Gate: return non-empty list of offending fragments if any secret survives redaction.
    Reuses the same patterns; UUIDs and '<REDACTED>' are not leaks."""
    leaks: list[str] = []
    for pat, mode in _PATS:
        for m in pat.finditer(blob):
            frag = m.group(0)
            if frag == "<REDACTED>" or (mode == "uuid_skip" and UUID.match(frag)):
                continue
            # key=value / "key":"value" forms whose value is already <REDACTED> are fine
            if frag.rstrip().endswith("<REDACTED>") or "<REDACTED>" in frag:
                continue
            leaks.append(frag[:12] + "…")
    return leaks

